import React, { FC } from 'react';
import { ImageFullscreenProps, ImageFullscreenPropsImg } from './ImageFullscreen.types';

import './ImageFullscreen.scss';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';

export const ImageFullscreen: FC<ImageFullscreenProps> = ({
	header,
	headline,
	image,
	withBackground = true,
	className,
	dataTestId = 'ImageFullscreen',
	...rest
}) => {
	const base = 'dsb_imagefullscreen';

	return (
		<section
			className={classNames(base, withBackground && `${base}-background`, className)}
			data-testid={dataTestId}
			{...rest}
		>
			{header && (
				<Typography variant={'h2'} className={`${base}__header`}>
					{header}
				</Typography>
			)}
			{headline && typeof headline === 'string' ? (
				<Typography inactive variant="body2" className={`${base}__headline`}>
					{headline}
				</Typography>
			) : (
				headline
			)}
			<div className={`${base}__image`}>
				{typeof image === 'object' && !React.isValidElement(image) ? <img loading="lazy" {...image} /> : image}
			</div>
		</section>
	);
};

export default ImageFullscreen;

export type { ImageFullscreenProps, ImageFullscreenPropsImg };
